+        "anthropic.get_usage",
+        &["anthropic.get_usage"],
+    );
+    let invoke = invoke_request(
+        "anthropic.chat",
+        json!({ "message": "blocked request" }),
+        token,
+    );
+
+    let dynamic = DynamicSuite {
+        config: json!({ "api_key": "test-anthropic-key" }),
+        handshake: handshake.clone(),
+        invoke: Some(invoke),
