+#[fcp_async_core::runtime::test]
+async fn google_ai_streaming_backpressure_is_deterministic() {
+    let mock = MockApiServer::start().await;
+
+    // Google AI streaming returns a JSON array of response chunks
+    let streaming_response = json!([
+        {
+            "candidates": [{
+                "content": {
+                    "parts": [{"text": "Hello"}],
+                    "role": "model"
+                },
+                "index": 0
+            }]
+        },
+        {
+            "candidates": [{
+                "content": {
+                    "parts": [{"text": " world"}],
+                    "role": "model"
+                },
+                "index": 0
+            }]
+        },
+        {
+            "candidates": [{
+                "content": {
+                    "parts": [{"text": "!"}],
+                    "role": "model"
+                },
+                "finishReason": "STOP",
+                "index": 0
+            }],
+            "usageMetadata": {
+                "promptTokenCount": 5,
+                "candidatesTokenCount": 3,
+                "totalTokenCount": 8
+            }
+        }
+    ]);
+
+    Mock::given(method("POST"))
+        .and(path(
+            "/v1beta/models/gemini-2.0-flash:streamGenerateContent",
+        ))
+        .and(query_param("key", "stream-test-key"))
+        .respond_with(ResponseTemplate::new(200).set_body_json(streaming_response))
+        .mount(mock.inner())
+        .await;
+
+    let client = GoogleAiClient::new("stream-test-key")
+        .expect("client init")
+        .with_base_url(&format!("{}/v1beta", mock.base_url()));
+
+    let body = json!({
+        "contents": [{"role": "user", "parts": [{"text": "hello"}]}]
+    });
+
+    let chunks = client
+        .generate_content_stream("gemini-2.0-flash", &body)
+        .await
+        .expect("stream request");
+
+    // Verify chunk count
+    assert_eq!(chunks.len(), 3, "expected 3 streaming chunks");
+
+    // Collect text from all chunks with inter-step delay (backpressure simulation)
+    let mut collected = String::new();
+    for chunk in &chunks {
+        for candidate in &chunk.candidates {
+            if let Some(content) = &candidate.content {
+                for part in &content.parts {
+                    if let fcp_google_ai::types::Part::Text { text } = part {
+                        collected.push_str(text);
+                    }
+                }
+            }
+        }
+        // Simulate backpressure by delaying between chunk processing
+        tokio::time::sleep(Duration::from_millis(8)).await;
+    }
+
+    assert_eq!(collected, "Hello world!");
+
+    // Verify usage metadata from the final chunk
+    let last_chunk = chunks.last().unwrap();
+    let usage = last_chunk.usage_metadata.as_ref().expect("usage metadata");
+    assert_eq!(usage.prompt_token_count, 5);
+    assert_eq!(usage.candidates_token_count, 3);
+
+    // Verify client tracked usage correctly
+    let client_usage = client.get_usage();
+    assert_eq!(client_usage.requests_total, 1);
+    assert_eq!(client_usage.requests_error, 0);
+    assert_eq!(client_usage.input_tokens, 5);
+    assert_eq!(client_usage.output_tokens, 3);
+}

